async function run(input) {
  const { pr_url, github_token } = input;
  // Parse owner/repo/number from URL
  const match = pr_url.match(/github\.com\/([^\/]+)\/([^\/]+)\/pull\/(\d+)/);
  if (!match) throw new Error('Invalid GitHub PR URL');
  const [, owner, repo, number] = match;
  const headers = { 'Accept': 'application/vnd.github.v3+json' };
  if (github_token) headers['Authorization'] = `token ${github_token}`;
  // Fetch PR metadata
  const meta = await fetch(`https://api.github.com/repos/${owner}/${repo}/pulls/${number}`, { headers }).then(r => r.json());
  // Fetch diff
  const diffRes = await fetch(`https://api.github.com/repos/${owner}/${repo}/pulls/${number}`, {
    headers: { ...headers, 'Accept': 'application/vnd.github.v3.diff' }
  });
  const diff = await diffRes.text();
  return {
    pr_title: meta.title,
    pr_description: meta.body || '',
    author: meta.user?.login || '',
    base_branch: meta.base?.ref || 'main',
    diff,
    files_changed: meta.changed_files,
    additions: meta.additions,
    deletions: meta.deletions
  };
}
